scription?'=>'¿Seguro que quieres cancelar tu suscripción?','Cancel Subscription'=>'Cancelar la suscripción','No active subscriptions'=>'No hay suscripciones activas','Status/Note'=>'Estado/Nota','Membership Level'=>'Nivel de membresía','Amount'=>'Cantidad','Subscriber ID'=>'ID del suscriptor','Transaction ID'=>'ID de transacción','Date'=>'Fecha','Member Profile'=>'Perfil de miembro','Last Name'=>'Apellidos','First Name'=>'Nombre','Email Address'=>'Dirección de correo electrónico','View Profile'=>'Ver perfil','The selected entry was deleted!'=>'¡La entrada seleccionada fue borrada!','Delete'=>'Borrar','Button Shortcode'=>'Botón del shortcode','Button Type'=>'Tipo de botón','Membership Level ID'=>'ID de nivel de membresía','Payment Button Title'=>'Título del botón de pago','Payment Button ID'=>'ID del botón de pago','smp7, wp.insider'=>'smp7, wp.insider','A flexible, well-supported, and easy-to-use WordPress membership plugin for offering free and premium content from your WordPress site.'=>'Un plugin de membresía de WordPress flexible, bien apoyado y fácil de usar para ofrecer contenido gratuito y de pago desde tu sitio de WordPress.','https://simple-membership-plugin.com/'=>'https://simple-membership-plugin.com/']];